/**
 * Latency probe: unknown
 *
 * AUTO-GENERATED by Phase 7-D ExperimentAuthorExperiment from a
 * brief in self_findings with category='experiment_proposal'.
 *
 * Hypothesis: unknown p50 latency stays below 120002ms on the rolling 200-call window.
 *
 * Template: model_latency_probe
 * Model: unknown
 * Rolling sample: 5
 */

import type {
  Experiment,
  ExperimentContext,
  Finding,
  ProbeResult,
  Verdict,
} from '../experiment-types.js';

interface UnknownLatencyExperimentEvidence extends Record<string, unknown> {
  model: string;
  samples: number;
  p50_latency_ms: number;
  mean_latency_ms: number;
  max_latency_ms: number;
  min_samples_required: number;
  warn_threshold_ms: number;
  fail_threshold_ms: number;
}

interface UnknownLatencyExperimentRow {
  latency_ms: number;
}

export class UnknownLatencyExperiment implements Experiment {
  id = 'unknown-latency';
  name = 'Latency probe: unknown';
  category = 'model_health' as const;
  hypothesis = 'unknown p50 latency stays below 120002ms on the rolling 200-call window.';
  cadence = { everyMs: 1800000, runOnBoot: false };

  async probe(ctx: ExperimentContext): Promise<ProbeResult> {
    const { data } = await ctx.db
      .from<UnknownLatencyExperimentRow>('llm_calls')
      .select('latency_ms')
      .eq('model', 'unknown')
      .order('created_at', { ascending: false })
      .limit(5);

    const rows = (data ?? []) as UnknownLatencyExperimentRow[];
    const latencies = rows.map((r) => r.latency_ms).filter((v) => typeof v === 'number' && v >= 0);

    const samples = latencies.length;
    const sorted = [...latencies].sort((a, b) => a - b);
    const p50 = sorted.length > 0 ? sorted[Math.floor(sorted.length / 2)] : 0;
    const mean = latencies.length > 0 ? Math.round(latencies.reduce((a, b) => a + b, 0) / latencies.length) : 0;
    const max = latencies.length > 0 ? Math.max(...latencies) : 0;

    const evidence: UnknownLatencyExperimentEvidence = {
      model: 'unknown',
      samples,
      p50_latency_ms: p50,
      mean_latency_ms: mean,
      max_latency_ms: max,
      min_samples_required: 5,
      warn_threshold_ms: 120002,
      fail_threshold_ms: 120502,
    };

    const summary =
      samples < 5
        ? `insufficient samples for ${'unknown'}: ${samples} < ${5}`
        : `${'unknown'}: p50 ${p50}ms over ${samples} calls (warn=120002, fail=120502)`;

    return {
      subject: `model:${'unknown'}`,
      summary,
      evidence,
    };
  }

  judge(result: ProbeResult, _history: Finding[]): Verdict {
    const ev = result.evidence as UnknownLatencyExperimentEvidence;
    if (ev.samples < ev.min_samples_required) return 'warning';
    if (ev.p50_latency_ms >= ev.fail_threshold_ms) return 'fail';
    if (ev.p50_latency_ms >= ev.warn_threshold_ms) return 'warning';
    return 'pass';
  }
}
